import { Injectable } from '@angular/core';

import * as firebase from 'firebase';

/*
  Generated class for the AuthProvider provider.

  See https://angular.io/guide/dependency-injection for more info on providers
  and Angular DI.
*/
@Injectable()
export class AuthProvider {

  constructor() {
    console.log('Hello AuthProvider Provider');
  }

  login(email: string, password: string): Promise<any> {
        return firebase.auth().signInWithEmailAndPassword(email, password).then(() => {
              console.log('User logged in successfully')
        }).catch((err: Error) => {
              console.error('Counld NOT login user')
        })
  }

  signup(email: string, dept: string, password: string): Promise<any> {
        return firebase.auth().createUserWithEmailAndPassword(email, password).then(() => {
              console.log('User createed successfully')

              firebase.database().ref(`Users/${dept}`).set({
                    email: email,
                    sentFiles: [],
                    receivedFiles: []
              }).then(() => {
                    console.log('User added to the database');
              }).catch((err: Error) => {
                    console.error('User could NOT be added to the database: \n Reason: ', err.message)
              })
        }).catch((err: Error) => {
            console.error('User account could NOT be created: \n Reason: ', err.message)
        })
  }

  logout(): Promise<any> {
        return firebase.auth().signOut()
  }

}



