import { Component } from '@angular/core';
import { Platform } from 'ionic-angular';
import { StatusBar } from '@ionic-native/status-bar';
import { SplashScreen } from '@ionic-native/splash-screen';

import { HomePage } from '../pages/home/home';
import { HeroPage } from '../pages/hero/hero';
import { FileEditorPage } from '../pages/file-editor/file-editor';
import { FileViewerPage } from '../pages/file-viewer/file-viewer';
import { LoginPage } from '../pages/login/login';
import { SendFilesPage } from '../pages/send-files/send-files';
import { SignupPage } from '../pages/signup/signup';
@Component({
  templateUrl: 'app.html'
})
export class MyApp {
  rootPage:any = HeroPage;

  constructor(platform: Platform, statusBar: StatusBar, splashScreen: SplashScreen) {
    platform.ready().then(() => {
      // Okay, so the platform is ready and our plugins are available.
      // Here you can do any higher level native things you might need.
      statusBar.styleDefault();
      splashScreen.hide();
    });
  }
}




