import { Component } from '@angular/core';
import { NavController, ModalController } from 'ionic-angular';
import { FileViewerPage } from '../file-viewer/file-viewer';
import { SendFilesPage } from '../send-files/send-files';
import { AuthProvider } from '../../providers/auth/auth';
import { AddRecordPage } from '../add-record/add-record';
import { HeroPage } from '../hero/hero';
import { RecordsPage } from '../records/records';

@Component({
  selector: 'page-home',
  templateUrl: 'home.html',
  providers: [AuthProvider]
})
export class HomePage {
      receivedFiles: any[] = [
            {
                  title: 'File One',
                  content: 'Lorem ipsum dolor sit amet...',
                  sent: '8th October, 2018',
                  from: 'Legal'
            },
            {
                  title: 'File Two',
                  content: 'Lorem ipsum dolor sit amet...',
                  sent: '9th October, 2018',
                  from: 'Marketing'
            },
      ];
      sentFiles: any[] = [
            {
                  title: 'File One',
                  content: 'Lorem ipsum dolor sit amet...',
                  sent: '8th October, 2018',
                  from: 'Legal'
            },
            {
                  title: 'File Two',
                  content: 'Lorem ipsum dolor sit amet...',
                  sent: '9th October, 2018',
                  from: 'Marketing'
            },
      ];
  constructor(public navCtrl: NavController, private auth: AuthProvider, private modal: ModalController) {

  }

  viewRFile(i: number) {
        this.navCtrl.push(FileViewerPage, {file: this.receivedFiles[i]})
  }

  viewSFile(i: number) {
      this.navCtrl.push(FileViewerPage, {file: this.sentFiles[i]})
}

toSendPage() {
      this.navCtrl.push(SendFilesPage)
}

addRecord() {
      this.modal.create(AddRecordPage).present()
}

toRecords() {
      this.navCtrl.push(RecordsPage)
}

logout() {
      this.auth.logout().then(() => {
            console.log('User Logged out')
            this.navCtrl.setRoot(HeroPage)
      })
}

}



