import { Component } from '@angular/core';
import { IonicPage, NavController, NavParams, LoadingController } from 'ionic-angular';
import { FileProvider } from '../../providers/file/file';
import { LoaderProvider } from '../../providers/loader/loader';

/**
 * Generated class for the AddRecordPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@IonicPage()
@Component({
  selector: 'page-add-record',
  templateUrl: 'add-record.html',
  providers: [FileProvider, LoaderProvider]
})
export class AddRecordPage {
      fileNo: any;
      date: string = Date.now().toLocaleString();
      to;
      from;
      subject;
      signature;

  constructor(public navCtrl: NavController, public navParams: NavParams, private fileProvider: FileProvider, private loader: LoadingController) {
  }

  add() {
        let loader = this.loader.create({
              content: 'Adding Record'
        })
        loader.present();
        var details = {
              date: this.date,
              to: this.to,
              from: this.from,
              subject: this.subject,
              signature: this.signature,
              fileNo: this.fileNo
        }
      //   add record to firebase using file provider
      this.fileProvider.addRecord(details).then(() => {
            loader.dismiss()
            this.date = '',
              this.to = '',
              this.from = '',
              this.subject = '',
              this.signature = '',
              this.fileNo = ''
      })
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad AddRecordPage');
  }

}



