import { Component } from '@angular/core';
import { IonicPage, NavController, NavParams, LoadingController } from 'ionic-angular';
import * as firebase from 'firebase/app'

/**
 * Generated class for the RecordsPage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@IonicPage()
@Component({
  selector: 'page-records',
  templateUrl: 'records.html',
})
export class RecordsPage {
      records: any[] = []

  constructor(public navCtrl: NavController, public navParams: NavParams, private loader: LoadingController) {
        this.getRecords()
  }

  getRecords() {
      let loader = this.loader.create({
            content: 'Loading Records'
      })
      loader.present();
      firebase.database().ref('Records/').on('value', (snap) => {
            for (const key in snap.val()) {
                  if (snap.val().hasOwnProperty(key)) {
                        const record = snap.val()[key];
                        this.records.push(record)
                  }
            }
            loader.dismiss()
      })
  }

  ionViewDidLoad() {
    console.log('ionViewDidLoad RecordsPage');
  }

}



